import React from "react";
import { Link } from "react-router-dom";
import api from "../api/api";   // ✅ fixed path

const FreelancerLayout = ({ children }) => {
  return (
    <div className="flex min-h-screen bg-gray-100">

      {/* Sidebar */}
      <div className="w-64 bg-white shadow-md p-6">
        <h2 className="text-xl font-bold mb-6">Freelancer</h2>

        <nav className="space-y-4">
          <Link to="/freelancer/dashboard">Dashboard</Link>
          <Link to="/freelancer/projects">Projects</Link>
          <Link to="/freelancer/proposals">Proposals</Link>
          <Link to="/freelancer/profile">Profile</Link>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8">
        {children}
      </div>
    </div>
  );
};

export default FreelancerLayout;
